var DIALOGE = [
{"id": "dlg_001", "cat": "Telefongespräch", "q": {"de": "Könnten Sie mich bitte mit Herrn / Frau … verbinden?", "en": "Could you please connect me with Mr. / Ms. …?", "uk": "Чи не могли б ви з'єднати мене з паном / пані …?", "ru": "Не могли бы вы соединить меня с господином / госпожой …?"}, "a": {"de": "Ja, natürlich. Einen Moment bitte, ich verbinde Sie.", "en": "Yes, of course. One moment please, I'll connect you.", "uk": "Так, звичайно. Хвилинку, будь ласка, я вас з'єдную.", "ru": "Да, конечно. Одну минуту, я вас соединяю."}},
{"id": "dlg_002", "cat": "Telefongespräch", "q": {"de": "Ich glaube, ich habe nicht die richtige Durchwahl. Ich suche Herrn / Frau …", "en": "I think I have the wrong extension. I'm looking for Mr. / Ms. …", "uk": "Здається, у мене не той додатковий номер. Я шукаю пана / пані …", "ru": "Кажется, у меня не тот добавочный номер. Я ищу господина / госпожу …"}, "a": {"de": "Kein Problem. Ich stelle Sie durch. Bitte bleiben Sie in der Leitung.", "en": "No problem. I'll transfer you. Please hold the line.", "uk": "Не проблема. Я вас переключу. Будь ласка, залишайтеся на лінії.", "ru": "Не проблема. Я вас переключу. Пожалуйста, оставайтесь на линии."}},
{"id": "dlg_003", "cat": "Telefongespräch", "q": {"de": "Könnten Sie Frau … etwas ausrichten? Sie ist leider gerade nicht erreichbar.", "en": "Could you pass a message to Ms. …? She is unfortunately not available right now.", "uk": "Чи могли б ви передати щось пані …? На жаль, вона зараз недоступна.", "ru": "Не могли бы вы передать кое-что госпоже …? К сожалению, она сейчас недоступна."}, "a": {"de": "Ja, selbstverständlich. Was soll ich ihr ausrichten?", "en": "Yes, of course. What would you like me to tell her?", "uk": "Так, звичайно. Що мені їй передати?", "ru": "Да, конечно. Что мне ей передать?"}},
{"id": "dlg_004", "cat": "Telefongespräch", "q": {"de": "Ich bin mir nicht ganz sicher, ob ich Sie richtig verstanden habe. Könnten Sie das bitte wiederholen?", "en": "I'm not quite sure I understood you correctly. Could you please repeat that?", "uk": "Я не зовсім впевнений, чи правильно я вас зрозумів. Не могли б ви повторити?", "ru": "Я не совсем уверен, правильно ли я вас понял. Не могли бы вы повторить?"}, "a": {"de": "Natürlich. Ich sagte: … Ist das jetzt verständlich?", "en": "Of course. I said: … Is that clear now?", "uk": "Звичайно. Я сказав: … Тепер зрозуміло?", "ru": "Конечно. Я сказал: … Теперь понятно?"}},
{"id": "dlg_005", "cat": "Telefongespräch", "q": {"de": "Melden Sie sich gerne wieder, wenn Sie weitere Auskünfte benötigen.", "en": "Feel free to contact us again if you need further information.", "uk": "Звертайтеся знову, якщо вам знадобиться додаткова інформація.", "ru": "Обращайтесь снова, если вам понадобится дополнительная информация."}, "a": {"de": "Vielen Dank, das werde ich tun. Auf Wiederhören!", "en": "Thank you very much, I will do that. Goodbye!", "uk": "Дуже дякую, обов'язково. До побачення!", "ru": "Большое спасибо, так и сделаю. До свидания!"}},
{"id": "dlg_006", "cat": "Messe", "q": {"de": "Kann ich Ihnen behilflich sein?", "en": "Can I help you?", "uk": "Чи можу я вам чимось допомогти?", "ru": "Могу ли я вам чем-нибудь помочь?"}, "a": {"de": "Ja, gerne. Ich interessiere mich für … Können Sie mir mehr darüber erzählen?", "en": "Yes, please. I'm interested in … Can you tell me more about it?", "uk": "Так, із задоволенням. Мене цікавить … Можете розповісти докладніше?", "ru": "Да, с удовольствием. Меня интересует … Можете рассказать подробнее?"}},
{"id": "dlg_007", "cat": "Messe", "q": {"de": "Kommen Sie auch aus dem … bereich / der … branche?", "en": "Are you also from the … sector / industry?", "uk": "Ви також із галузі …?", "ru": "Вы тоже из сферы …?"}, "a": {"de": "Ja, genau. Wir sind im Bereich … tätig. Und Sie?", "en": "Yes, exactly. We work in the … sector. And you?", "uk": "Так, саме так. Ми працюємо у сфері … А ви?", "ru": "Да, именно. Мы работаем в сфере … А вы?"}},
{"id": "dlg_008", "cat": "Messe", "q": {"de": "Wir haben hier etwas ganz Besonderes. Es hat den Vorteil, dass …", "en": "We have something very special here. It has the advantage that …", "uk": "У нас тут є щось особливе. Воно має ту перевагу, що …", "ru": "У нас здесь есть кое-что особенное. Оно имеет то преимущество, что …"}, "a": {"de": "Das klingt interessant. Können Sie mir das genauer erklären?", "en": "That sounds interesting. Could you explain that in more detail?", "uk": "Це звучить цікаво. Чи могли б ви пояснити детальніше?", "ru": "Это звучит интересно. Не могли бы вы объяснить подробнее?"}},
{"id": "dlg_009", "cat": "Messe", "q": {"de": "Ich kann Ihnen das gerne mal vorführen / demonstrieren. Sie dürfen es auch gerne ausprobieren.", "en": "I'd be happy to demonstrate it for you. You're also welcome to try it out.", "uk": "Я із задоволенням продемонструю вам це. Ви також можете спробувати.", "ru": "Я с удовольствием продемонстрирую вам это. Вы также можете попробовать."}, "a": {"de": "Oh, sehr gerne! Das würde mich sehr interessieren.", "en": "Oh, I'd love that! I'm very interested.", "uk": "О, із задоволенням! Мені це дуже цікаво.", "ru": "О, с удовольствием! Мне это очень интересно."}},
{"id": "dlg_010", "cat": "Messe", "q": {"de": "Wir haben damit sehr gute Erfahrungen gemacht. Das Material ist aus … und hat besondere Eigenschaften.", "en": "We have had very good experience with this. The material is made of … and has special properties.", "uk": "Ми маємо дуже хороший досвід роботи з цим. Матеріал виготовлений з … і має особливі властивості.", "ru": "У нас очень хороший опыт работы с этим. Материал сделан из … и имеет особые свойства."}, "a": {"de": "Das ist beeindruckend. Gibt es das auch in anderen Ausführungen?", "en": "That's impressive. Is it also available in other versions?", "uk": "Це вражає. Чи є воно в інших варіантах виконання?", "ru": "Это впечатляет. Есть ли оно в других исполнениях?"}},
{"id": "dlg_011", "cat": "Messe", "q": {"de": "Kann ich Ihnen eine kleine Erfrischung anbieten?", "en": "Can I offer you a small refreshment?", "uk": "Чи можу я запропонувати вам напої або перекусити?", "ru": "Могу ли я предложить вам что-нибудь освежиться?"}, "a": {"de": "Ja, gerne. Vielen Dank für das Angebot.", "en": "Yes, please. Thank you very much for the offer.", "uk": "Так, із задоволенням. Дуже дякую за пропозицію.", "ru": "Да, с удовольствием. Большое спасибо за предложение."}},
{"id": "dlg_012", "cat": "Messe", "q": {"de": "Wenn Sie möchten, kann ich Ihnen gerne Informationsmaterial zuschicken. Dürfen wir Sie auch über neue Produkte informieren?", "en": "If you'd like, I can send you some information material. May we also inform you about new products?", "uk": "Якщо бажаєте, я можу надіслати вам інформаційні матеріали. Чи можемо ми інформувати вас про нові продукти?", "ru": "Если хотите, я могу выслать вам информационные материалы. Можем ли мы информировать вас о новых продуктах?"}, "a": {"de": "Ja, das wäre sehr nett. Hier ist meine Visitenkarte.", "en": "Yes, that would be very kind. Here is my business card.", "uk": "Так, це було б дуже люб'язно. Ось моя візитка.", "ru": "Да, это было бы очень любезно. Вот моя визитная карточка."}},
{"id": "dlg_013", "cat": "Messe", "q": {"de": "Könnten Sie mir bitte bei / mit … weiterhelfen?", "en": "Could you please help me with …?", "uk": "Чи не могли б ви мені допомогти з …?", "ru": "Не могли бы вы помочь мне с …?"}, "a": {"de": "Selbstverständlich, das mache ich gerne. Womit genau kann ich Ihnen helfen?", "en": "Of course, I'd be happy to. What exactly can I help you with?", "uk": "Звичайно, із задоволенням. З чим саме я можу вам допомогти?", "ru": "Конечно, с удовольствием. Чем именно я могу вам помочь?"}},
{"id": "dlg_014", "cat": "Lösungswege diskutieren", "q": {"de": "Also, wir haben die Herausforderung, dass die Lieferzeiten sich ständig verzögern. Das Hauptproblem sehe ich darin, dass der Lieferant nicht zuverlässig informiert.", "en": "So, we have the challenge that delivery times keep getting delayed. I see the main problem in the fact that the supplier doesn't inform us reliably.", "uk": "Отже, ми маємо таку проблему, що терміни доставки постійно затримуються. Головну проблему я бачу в тому, що постачальник не надає надійної інформації.", "ru": "Итак, у нас такая проблема, что сроки доставки постоянно задерживаются. Главную проблему я вижу в том, что поставщик не предоставляет надёжной информации."}, "a": {"de": "Habe ich dich richtig verstanden: Es geht also vor allem um die schlechte Kommunikation mit dem Lieferanten?", "en": "Did I understand you correctly: it's mainly about the poor communication with the supplier?", "uk": "Я правильно тебе зрозумів(ла): отже, йдеться передусім про погану комунікацію з постачальником?", "ru": "Я правильно тебя понял(а): значит, речь идёт прежде всего о плохой коммуникации с поставщиком?"}},
{"id": "dlg_015", "cat": "Lösungswege diskutieren", "q": {"de": "Genau. Welche Folgen hätte das deiner Meinung nach, wenn wir das Problem nicht lösen?", "en": "Exactly. What consequences do you think this would have if we don't solve the problem?", "uk": "Саме так. Які наслідки це матиме, на твою думку, якщо ми не вирішимо проблему?", "ru": "Именно так. Какие последствия это будет иметь, по-твоему, если мы не решим проблему?"}, "a": {"de": "Was könnten wir in dieser Situation machen? Hast du einen Vorschlag, wie wir vorgehen sollten?", "en": "What could we do in this situation? Do you have a suggestion on how we should proceed?", "uk": "Що ми могли б зробити в цій ситуації? Чи маєш ти пропозицію, як нам варто діяти?", "ru": "Что мы могли бы сделать в этой ситуации? Есть ли у тебя предложение, как нам следует действовать?"}},
{"id": "dlg_016", "cat": "Lösungswege diskutieren", "q": {"de": "Ich habe eine Idee bzw. einen Vorschlag: Wir könnten zum Beispiel einen zweiten Lieferanten als Backup einplanen.", "en": "I have an idea or a suggestion: we could, for example, plan a second supplier as a backup.", "uk": "У мене є ідея або пропозиція: ми могли б, наприклад, запланувати другого постачальника як резервний варіант.", "ru": "У меня есть идея или предложение: мы могли бы, например, запланировать второго поставщика в качестве резерва."}, "a": {"de": "Sinnvoll wäre es, wenn wir das kurzfristig testen. Eine Alternative wäre auch, die Lagerbestände zu erhöhen.", "en": "It would make sense if we tested that in the short term. An alternative would also be to increase stock levels.", "uk": "Було б доцільно, якби ми перевірили це в короткостроковій перспективі. Альтернативою було б також збільшити запаси на складі.", "ru": "Было бы целесообразно, если бы мы проверили это в краткосрочной перспективе. Альтернативой также было бы увеличить запасы на складе."}},
{"id": "dlg_017", "cat": "Lösungswege diskutieren", "q": {"de": "Was hältst du davon, beide Maßnahmen gleichzeitig umzusetzen? Wie siehst du das?", "en": "What do you think about implementing both measures at the same time? How do you see it?", "uk": "Що ти думаєш про те, щоб реалізувати обидва заходи одночасно? Як ти це бачиш?", "ru": "Что ты думаешь о том, чтобы реализовать обе меры одновременно? Как ты это видишь?"}, "a": {"de": "Ich bin der Meinung, dass das zu viel auf einmal wäre. Aus meiner Sicht spricht dafür, dass wir erst den zweiten Lieferanten testen.", "en": "I think that would be too much at once. From my point of view, it speaks in favor of first testing the second supplier.", "uk": "Я вважаю, що це було б занадто багато одночасно. На мою думку, на користь цього говорить те, що варто спочатку перевірити другого постачальника.", "ru": "Я считаю, что это было бы слишком много одновременно. На мой взгляд, в пользу этого говорит то, что нужно сначала проверить второго поставщика."}},
{"id": "dlg_018", "cat": "Lösungswege diskutieren", "q": {"de": "Dagegen spricht aber, dass uns das Zeit kostet. Wärst du damit einverstanden, beide Schritte parallel zu starten?", "en": "But the argument against that is that it costs us time. Would you agree to start both steps in parallel?", "uk": "Але проти цього говорить те, що це коштує нам часу. Ти був(ла) б з цим згоден(на) розпочати обидва кроки паралельно?", "ru": "Но против этого говорит то, что это стоит нам времени. Ты был(а) бы согласен(на) начать оба шага параллельно?"}, "a": {"de": "Das klingt überzeugend. Damit bin ich einverstanden, weil wir so schneller eine Lösung finden.", "en": "That sounds convincing. I agree with that, because that way we'll find a solution faster.", "uk": "Це звучить переконливо. Я з цим згоден(на), тому що так ми швидше знайдемо рішення.", "ru": "Это звучит убедительно. Я с этим согласен(на), потому что так мы быстрее найдём решение."}},
{"id": "dlg_019", "cat": "Lösungswege diskutieren", "q": {"de": "Gute Idee, allerdings sollten wir auch bedenken, dass die Geschäftsführung zustimmen muss. Ich sehe das anders: Wir sollten zuerst einen kurzen Bericht vorbereiten.", "en": "Good idea, however we should also consider that management has to agree. I see it differently: we should first prepare a short report.", "uk": "Гарна ідея, проте нам також слід врахувати, що керівництво має погодитися. Я бачу це інакше: спочатку нам слід підготувати короткий звіт.", "ru": "Хорошая идея, однако нам также следует учесть, что руководство должно дать согласие. Я вижу это иначе: сначала нам нужно подготовить короткий отчёт."}, "a": {"de": "Lass uns folgende Punkte festhalten: Bericht, Kostenübersicht und Zeitplan. Worauf können wir uns einigen?", "en": "Let's note down the following points: report, cost overview and schedule. What can we agree on?", "uk": "Давай зафіксуємо такі пункти: звіт, огляд витрат і графік. На чому ми можемо домовитися?", "ru": "Давай зафиксируем следующие пункты: отчёт, обзор расходов и график. О чём мы можем договориться?"}},
{"id": "dlg_020", "cat": "Lösungswege diskutieren", "q": {"de": "Wir priorisieren zuerst den Bericht, danach den Zeitplan. Wer übernimmt welche Aufgabe? Bis wann?", "en": "We prioritize the report first, then the schedule. Who takes on which task? By when?", "uk": "Ми спочатку надаємо пріоритет звіту, потім графіку. Хто бере на себе яке завдання? До якого терміну?", "ru": "Мы сначала отдаём приоритет отчёту, затем графику. Кто берёт на себя какую задачу? К какому сроку?"}, "a": {"de": "Als Kompromiss könnten wir die Aufgaben zu zweit aufteilen. Wenn wir bis Freitag liefern, wäre das für dich akzeptabel?", "en": "As a compromise, we could split the tasks between the two of us. If we deliver by Friday, would that be acceptable for you?", "uk": "Як компроміс, ми могли б розподілити завдання на двох. Якщо ми зробимо це до п'ятниці, це буде для тебе прийнятно?", "ru": "В качестве компромисса мы могли бы разделить задачи на двоих. Если мы сдадим к пятнице, это будет для тебя приемлемо?"}},
{"id": "dlg_021", "cat": "Lösungswege diskutieren", "q": {"de": "Wir könnten einen Mittelweg finden, indem wir den Bericht gemeinsam schreiben und den Zeitplan getrennt erstellen.", "en": "We could find a middle ground by writing the report together and creating the schedule separately.", "uk": "Ми могли б знайти золоту середину, якщо напишемо звіт спільно, а графік складемо окремо.", "ru": "Мы могли бы найти золотую середину, если напишем отчёт совместно, а график составим раздельно."}, "a": {"de": "Fassen wir zusammen: Wir werden den Bericht zusammen schreiben. Also, wir machen das jetzt so: Ich kümmere mich um den Zeitplan.", "en": "Let's summarize: we will write the report together. So, this is how we'll do it now: I'll take care of the schedule.", "uk": "Підсумуємо: ми будемо писати звіт разом. Отже, ми зробимо так: я займуся графіком.", "ru": "Подведём итог: мы будем писать отчёт вместе. Итак, мы сделаем так: я займусь графиком."}},
{"id": "dlg_022", "cat": "Lösungswege diskutieren", "q": {"de": "Nächste Schritte sind: Bericht fertigstellen, verantwortlich ist Herr Schmidt, Termin: Freitag. Was meinst du genau mit ‚fertigstellen'?", "en": "Next steps are: finalize the report, Mr. Schmidt is responsible, deadline: Friday. What exactly do you mean by 'finalize'?", "uk": "Наступні кроки: завершити звіт, відповідальний — пан Шмідт, термін: п'ятниця. Що саме ти маєш на увазі під «завершити»?", "ru": "Следующие шаги: завершить отчёт, ответственный — господин Шмидт, срок: пятница. Что именно ты имеешь в виду под «завершить»?"}, "a": {"de": "Damit meine ich, dass alle Zahlen geprüft und das Dokument an die Geschäftsführung gesendet wurde. Danke, dann sind wir uns einig.", "en": "By that I mean that all the figures have been checked and the document has been sent to management. Thank you, then we agree.", "uk": "Цим я маю на увазі, що всі цифри перевірені й документ надіслано керівництву. Дякую, тоді ми домовилися.", "ru": "Этим я имею в виду, что все цифры проверены и документ отправлен руководству. Спасибо, тогда мы договорились."}}
];


